const dataElement=document.getElementById("speakers-data"),evntImages=document.querySelectorAll(".event-speakers img"),speakerModal=document.getElementById("speaker-modal"),speakerContent=document.getElementById("speaker-content");if(dataElement){const mapData=JSON.parse(dataElement.textContent),{speakers:speakers}=mapData;evntImages.forEach((evntImage=>{evntImage.addEventListener("click",(()=>{const speaker=speakers.find((item=>item.id===evntImage.dataset.id));if(!speaker)return;speakerModal.heading=`${speaker.first_name} ${speaker.last_name}`,speakerContent.innerHTML=speaker.content;const oldSubHeading=document.querySelector("#speaker-modal .sub-heading");oldSubHeading&&oldSubHeading.remove();const subHeadingHtml=`\n               <div class="sub-heading">\n               <div class="spacer x-small"></div>\n               <p id="speaker-job-title">${speaker.job_title}</p>\n               <div class="spacer small"></div>\n               <div class="event-card-wrap">\n                    <div class="grid-x">\n                    <i class="icon-email-1"></i>\n                    <span id="speaker-email">${speaker.contact.email}</span>\n                    </div>\n               </div>\n               </div>\n               `;document.querySelector("#speaker-modal .icon-close-1").insertAdjacentHTML("afterend",subHeadingHtml),speakerModal.open()}))}))}